g.replace("[30m", "\x1b[30m") |> String.replace("[31m", "\x1b[31m") |> String.replace("[32m", "\x1b[32m") |> String.replace("[33m", "\x1b[33m") |> String.replace("[34m", "\x1b[34m") |> String.replace("[35m", "\x1b[35m") |> String.replace("[36m", "\x1b[36m") |> String.replace("[37m", "\x1b[37m") end defp get_terminal_width(config) do case System.cmd("tput", ["cols"]) do {result, 0} -> width = String.trim(result) |> String.to_integer() min(width, config.max_width) _ -> config.max_width end end defp display_welcome_message(config) do IO.puts """ #{config.colors.green}Welcome to your friendly Terminal Chatbot! 🌟#{config.colors.reset} #{config.colors.magenta}Here to assist you with coding and more, with a touch of fun!#{config.colors.reset} #{config.colors.blue}Type your messages and press Enter to chat.#{config.colors.reset} #{config.colors.blue}Type 'exit' or 'quit' to end the conversation.#{config.colors.reset} #{config.colors.blue}Press Ctrl+C to exit at any time.#{config.colors.reset} #{config.colors.green}----------------------------------------------------#{config.colors.reset} """ end end ChatbotFormatter.run() can you fix my code please here's where i'm at so far ok for the next problem, i am using plain Vim in the terminal on mac, using all its main advanced features like the Ntree and integrated terminal in normal mode, which works great, and i even get sytax highlihghting. However when i use chat apps in the terminal, they do wrap around fine when it's set to small custom width, but they do not word wrap or move the WHOLE word to the next line, this part i dont like 🖥️ Vim Terminal Operations Guide 📟 Opening Terminal in Vim 🔓 Open terminal in current window: :term<Enter> or :terminal<Enter> ↕️ Open terminal in horizontal split: :split | term<Enter> ↔️ Open terminal in vertical split: :vsplit | term<Enter> or :vert term<Enter> 🔀 Navigating Between Vim and Terminal Splits 🔄 Switch to next split: Ctrl + w w or Ctrl + w Ctrl + w ⬅️➡️⬆️⬇️ Move to specific split: L